/*! Custom markdown parser | MIT License */
(function(root) {
  function marked(src) {
    src = src.replace(/\r\n|\r/g, '\n');
    var blocks = src.split(/\n{2,}/);
    var html = '';
    blocks.forEach(function(block) {
      block = block.trim();
      if (!block) return;
      var lines = block.split('\n');
      var paragraph = [];
      var ul = [];
      var ol = [];
      lines.forEach(function(line) {
        var h3 = line.match(/^###\s+(.+)/);
        if (h3) {
          if (paragraph.length) {
            html += '<p>' + inline(paragraph.join('<br>')) + '</p>'; paragraph = [];
          }
          if (ul.length) { html += '<ul>' + ul.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ul>'; ul = []; }
          if (ol.length) { html += '<ol>' + ol.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ol>'; ol = []; }
          html += '<h3>' + inline(h3[1].trim()) + '</h3>'; return;
        }
        var h2 = line.match(/^##\s+(.+)/);
        if (h2) {
          if (paragraph.length) {
            html += '<p>' + inline(paragraph.join('<br>')) + '</p>'; paragraph = [];
          }
          if (ul.length) { html += '<ul>' + ul.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ul>'; ul = []; }
          if (ol.length) { html += '<ol>' + ol.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ol>'; ol = []; }
          html += '<h2>' + inline(h2[1].trim()) + '</h2>'; return;
        }
        var h1 = line.match(/^#\s+(.+)/);
        if (h1) {
          if (paragraph.length) {
            html += '<p>' + inline(paragraph.join('<br>')) + '</p>'; paragraph = [];
          }
          if (ul.length) { html += '<ul>' + ul.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ul>'; ul = []; }
          if (ol.length) { html += '<ol>' + ol.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ol>'; ol = []; }
          html += '<h1>' + inline(h1[1].trim()) + '</h1>'; return;
        }
        var ulMatch = line.match(/^\s*[-*]\s+(.+)/);
        if (ulMatch) {
          if (paragraph.length) { html += '<p>' + inline(paragraph.join('<br>')) + '</p>'; paragraph = []; }
          if (ol.length) { html += '<ol>' + ol.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ol>'; ol = []; }
          ul.push(ulMatch[1]); return;
        }
        var olMatch = line.match(/^\s*\d+\.\s+(.+)/);
        if (olMatch) {
          if (paragraph.length) { html += '<p>' + inline(paragraph.join('<br>')) + '</p>'; paragraph = []; }
          if (ul.length) { html += '<ul>' + ul.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ul>'; ul = []; }
          ol.push(olMatch[1]); return;
        }
        paragraph.push(line);
      });
      if (ul.length) { html += '<ul>' + ul.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ul>'; }
      if (ol.length) { html += '<ol>' + ol.map(function(li){return '<li>' + inline(li) + '</li>';}).join('') + '</ol>'; }
      if (paragraph.length) { html += '<p>' + inline(paragraph.join('<br>')) + '</p>'; }
    });
    return html;
  }
  function inline(text) {
    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    text = text.replace(/\*(.+?)\*/g, '<em>$1</em>');
    text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
    return text;
  }
  root.marked = marked;
}(typeof window !== 'undefined' ? window : this));
